insert into public.catalog_records (object_name, title, culture_community, geographic_location, file_name, asset_format, record) values ('coll001', 'Untitled object 1', 'Bamana', 'Mali', '1.png', 'image/png', '{"Object name": "coll001", "Identifier": "", "Alternate ID": "", "Title": "Untitled object 1", "Alternate title(s)": "", "Replaces": "", "Replaced by": "", "Description": "Among the Bamana, oral traditions credit the mythical being Ci Wara (half mortal and half animal) with introducing agriculture to an agricultural society that still relies heavily on subsistence farming. Carved ci wara headdresses honor this being, who taught humans to cultivate the land before withdrawing into the earth when they became wasteful; his spirit was then enshrined in a boli and represented through these sculptures. The headdresses combine antelope features with those of animals like the aardvark and pangolin, whose natural behaviors mirror essential farming tasks, and they feature tapered antelope-inspired forms, aardvark references, and intricate openwork and geometric designs. Performed in male–female pairs by skilled dancers wearing long raffia costumes, ci wara masquerades praise and encourage farmers, symbolizing the elemental forces of sun, earth, water, and humanity, with women contributing through songs of praise. This particular work was acquired by Lawrence Arthur Jones, the first Chair of the Department of Art at Jackson State University.", "Creator": "", "Searchable date": "1900", "Date": "late 19th–early 20th century", "Coverage (time period)": "late 19th–early 20th century", "Time period": "", "Subject": "agriculture; mythology; fertility; performance; subsistence farming", "Mississippi county": "", "Geographic location": "Mali", "Resource type": "Physical Object", "Format": "", "Media format": "Object", "Language": "", "Language code": "", "Publisher": "Jackson State University. (electronic version); JSUMS ART. (electronic version)", "Contributors": "", "Notes": "", "Rights": "IN COPYRIGHT; http://rightsstatements.org/vocab/InC/1.0/", "Disclaimer": "All rights reserved. Reproduction or redistribution requires written permission from Jackson State University.", "Contributing institution": "Jackson State University.", "Collection": "Jackson State University African Art Collection.", "Source": "JSU Permanent Collection", "Digital repository": "JSUMS ART.", "Digital collection": "African Art, Jackson State University.", "File size": "", "File extension": "", "Width": "", "Height": "", "Color space": "", "Date digital": "", "Capture method": "", "Processing software": "", "Master image": "", "Record created by": "", "Hidden notes": "Scaffold record generated from the local object inventory. Review and replace provisional values during cataloging. Provisional title derived from numeric filename.", "Custom searches": "", "IP resolution": "", "Transcript": "", "File name": "1.png", "culture_community": "Bamana", "people_ethnolinguistic_group": "", "place_of_creation": "Mali", "place_of_use": "", "materials": "Carved wood", "technique": "", "object_type": "", "function_use": "", "period_dynasty": "late 19th–early 20th century", "provenance": "", "acquisition_context": "", "preferred_term": "", "legacy_title": "", "attribution_confidence": "", "cultural_sensitivity_note": "", "youtubeid": "", "vimeoid": "", "latitude": "17.5707", "longitude": "-3.9962", "format": "image/png"}'::jsonb) on conflict (object_name) do update set title = excluded.title, culture_community = excluded.culture_community, geographic_location = excluded.geographic_location, file_name = excluded.file_name, asset_format = excluded.asset_format, record = excluded.record;
insert into public.catalog_records (object_name, title, culture_community, geographic_location, file_name, asset_format, record) values ('coll002', 'Untitled object 2', 'Kongo or Teke', 'Democratic Republic of the Congo', '2.png', 'image/png', '{"Object name": "coll002", "Identifier": "", "Alternate ID": "", "Title": "Untitled object 2", "Alternate title(s)": "", "Replaces": "", "Replaced by": "", "Description": "This standing power figure is attributed to the Kongo cultural region and reflects the tradition of nkisi figures created to mediate between the human and spiritual realms. Such figures were activated through ritual practices conducted by ritual specialists and were believed to house spiritual forces capable of protection, healing, oath enforcement, and conflict resolution. The prominent abdominal bundle likely once contained sacred substances that endowed the figure with efficacy. The composed facial expression, upright posture, and material additions emphasize restraint, vigilance, and latent spiritual authority rather than overt aggression.", "Creator": "", "Searchable date": "1900", "Date": "late 19th–early 20th century", "Coverage (time period)": "late 19th–early 20th century", "Time period": "", "Subject": "spiritual power; protection; healing; ancestral mediation; ritual practice", "Mississippi county": "", "Geographic location": "Democratic Republic of the Congo", "Resource type": "Physical Object", "Format": "", "Media format": "Object", "Language": "", "Language code": "", "Publisher": "Jackson State University. (electronic version); JSUMS ART. (electronic version)", "Contributors": "", "Notes": "", "Rights": "IN COPYRIGHT; http://rightsstatements.org/vocab/InC/1.0/", "Disclaimer": "All rights reserved. Reproduction or redistribution requires written permission from Jackson State University.", "Contributing institution": "Jackson State University.", "Collection": "Jackson State University African Art Collection.", "Source": "JSu Permanent Collection", "Digital repository": "JSUMS ART.", "Digital collection": "African Art, Jackson State University.", "File size": "", "File extension": "", "Width": "", "Height": "", "Color space": "", "Date digital": "", "Capture method": "", "Processing software": "", "Master image": "", "Record created by": "", "Hidden notes": "Scaffold record generated from the local object inventory. Review and replace provisional values during cataloging. Provisional title derived from numeric filename.", "Custom searches": "", "IP resolution": "", "Transcript": "", "File name": "2.png", "culture_community": "Kongo or Teke", "people_ethnolinguistic_group": "", "place_of_creation": "Democratic Republic of the Congo", "place_of_use": "", "materials": "Carved wood, ritual materials", "technique": "", "object_type": "", "function_use": "", "period_dynasty": "late 19th–early 20th century", "provenance": "", "acquisition_context": "", "preferred_term": "", "legacy_title": "", "attribution_confidence": "", "cultural_sensitivity_note": "", "youtubeid": "", "vimeoid": "", "latitude": "-2.8797", "longitude": "23.6560", "format": "image/png"}'::jsonb) on conflict (object_name) do update set title = excluded.title, culture_community = excluded.culture_community, geographic_location = excluded.geographic_location, file_name = excluded.file_name, asset_format = excluded.asset_format, record = excluded.record;
insert into public.catalog_records (object_name, title, culture_community, geographic_location, file_name, asset_format, record) values ('coll003', 'Untitled object 3', 'Tabwa', 'Democratic Republic of the Congo', '3.png', 'image/png', '{"Object name": "coll003", "Identifier": "JA-2006-01", "Alternate ID": "", "Title": "Untitled object 3", "Alternate title(s)": "", "Replaces": "", "Replaced by": "", "Description": "This mask is attributed to the Tabwa people and reflects Central African traditions in which masks function as instruments of moral authority and ancestral presence. Characterized by geometric facial segmentation, narrow eyes, and a restrained expression, the mask emphasizes composure, wisdom, and social discipline rather than individual portraiture. Such masks were typically used in ceremonial contexts connected to initiation, funerary rites, or social regulation, where performance activated their meaning. The incised surface and dark patina suggest sustained ritual use and reinforce the mask’s role as a mediator between the living community and the ancestral realm.", "Creator": "", "Searchable date": "1900", "Date": "late 19th–early 20th century", "Coverage (time period)": "late 19th–early 20th century", "Time period": "", "Subject": "ancestral authority; moral instruction; initiation; funerary practices; performance", "Mississippi county": "", "Geographic location": "Democratic Republic of the Congo", "Resource type": "Physical Object", "Format": "", "Media format": "Object", "Language": "", "Language code": "", "Publisher": "Jackson State University. (electronic version); JSUMS ART. (electronic version)", "Contributors": "", "Notes": "Proposed institutional match based on visual comparison with accession image; pending catalog confirmation.", "Rights": "IN COPYRIGHT; http://rightsstatements.org/vocab/InC/1.0/", "Disclaimer": "All rights reserved. Reproduction or redistribution requires written permission from Jackson State University.", "Contributing institution": "Jackson State University.", "Collection": "Jackson State University African Art Collection.", "Source": "JSU permanent collection", "Digital repository": "JSUMS ART.", "Digital collection": "African Art, Jackson State University.", "File size": "", "File extension": "", "Width": "", "Height": "", "Color space": "", "Date digital": "", "Capture method": "", "Processing software": "", "Master image": "", "Record created by": "", "Hidden notes": "Scaffold record generated from the local object inventory. Review and replace provisional values during cataloging. Provisional title derived from numeric filename.", "Custom searches": "", "IP resolution": "", "Transcript": "", "File name": "3.png", "culture_community": "Tabwa", "people_ethnolinguistic_group": "", "place_of_creation": "Democratic Republic of the Congo", "place_of_use": "", "materials": "Carved wood", "technique": "", "object_type": "", "function_use": "", "period_dynasty": "late 19th–early 20th century", "provenance": "", "acquisition_context": "", "preferred_term": "", "legacy_title": "", "attribution_confidence": "", "cultural_sensitivity_note": "", "youtubeid": "", "vimeoid": "", "latitude": "-2.8797", "longitude": "23.6560", "format": "image/png"}'::jsonb) on conflict (object_name) do update set title = excluded.title, culture_community = excluded.culture_community, geographic_location = excluded.geographic_location, file_name = excluded.file_name, asset_format = excluded.asset_format, record = excluded.record;
insert into public.catalog_records (object_name, title, culture_community, geographic_location, file_name, asset_format, record) values ('coll004', 'Untitled object 4', 'Tabwa', 'Democratic Republic of the Congo', '4.png', 'image/png', '{"Object name": "coll004", "Identifier": "", "Alternate ID": "", "Title": "Untitled object 4", "Alternate title(s)": "", "Replaces": "", "Replaced by": "", "Description": "This wooden slit drum is carved in the form of a buffalo, an animal associated with strength, endurance, and social authority in Central African cultures. Among the Tabwa, such drums were used for communication and ritual purposes, including signaling, ceremonial performances, and community gatherings. The elongated body functions as a resonating chamber, while the carved zigzag motifs and stylized animal features emphasize both visual symbolism and acoustic function. The drum reflects the integration of sound, sculpture, and social meaning in Tabwa artistic traditions.", "Creator": "", "Searchable date": "1900", "Date": "late 19th–early 20th century", "Coverage (time period)": "late 19th–early 20th century", "Time period": "", "Subject": "communication; ritual sound; buffalo symbolism; community gatherings; social authority", "Mississippi county": "", "Geographic location": "Democratic Republic of the Congo", "Resource type": "Physical Object", "Format": "", "Media format": "Object", "Language": "", "Language code": "", "Publisher": "Jackson State University. (electronic version); JSUMS ART. (electronic version)", "Contributors": "", "Notes": "", "Rights": "IN COPYRIGHT; http://rightsstatements.org/vocab/InC/1.0/", "Disclaimer": "All rights reserved. Reproduction or redistribution requires written permission from Jackson State University.", "Contributing institution": "Jackson State University.", "Collection": "Jackson State University African Art Collection.", "Source": "JSU permanent collection", "Digital repository": "JSUMS ART.", "Digital collection": "African Art, Jackson State University.", "File size": "", "File extension": "", "Width": "", "Height": "", "Color space": "", "Date digital": "", "Capture method": "", "Processing software": "", "Master image": "", "Record created by": "", "Hidden notes": "Scaffold record generated from the local object inventory. Review and replace provisional values during cataloging. Provisional title derived from numeric filename.", "Custom searches": "", "IP resolution": "", "Transcript": "", "File name": "4.png", "culture_community": "Tabwa", "people_ethnolinguistic_group": "", "place_of_creation": "Democratic Republic of the Congo", "place_of_use": "", "materials": "Carved wood", "technique": "", "object_type": "", "function_use": "", "period_dynasty": "late 19th–early 20th century", "provenance": "", "acquisition_context": "", "preferred_term": "", "legacy_title": "", "attribution_confidence": "", "cultural_sensitivity_note": "", "youtubeid": "", "vimeoid": "", "latitude": "-2.8797", "longitude": "23.6560", "format": "image/png"}'::jsonb) on conflict (object_name) do update set title = excluded.title, culture_community = excluded.culture_community, geographic_location = excluded.geographic_location, file_name = excluded.file_name, asset_format = excluded.asset_format, record = excluded.record;
insert into public.catalog_records (object_name, title, culture_community, geographic_location, file_name, asset_format, record) values ('coll005', 'Untitled object 5', 'Tabwa', 'Democratic Republic of the Congo', '5.png', 'image/png', '{"Object name": "coll005", "Identifier": "JA-2006-02", "Alternate ID": "", "Title": "Untitled object 5", "Alternate title(s)": "", "Replaces": "", "Replaced by": "", "Description": "This carved wooden mask represents a buffalo, an animal associated among the Tabwa with strength, endurance, and controlled social authority. Buffalo imagery conveys moral power exercised with restraint and is often linked to protection, communal responsibility, and the enforcement of social norms. Such masks were used in ceremonial performances where animal symbolism embodied ancestral presence and ethical discipline within the community.", "Creator": "", "Searchable date": "1890", "Date": "late 19th century", "Coverage (time period)": "late 19th century", "Time period": "", "Subject": "buffalo symbolism; social authority; protection; communal responsibility; performance", "Mississippi county": "", "Geographic location": "Democratic Republic of the Congo", "Resource type": "Physical Object", "Format": "", "Media format": "Object", "Language": "", "Language code": "", "Publisher": "Jackson State University. (electronic version); JSUMS ART. (electronic version)", "Contributors": "", "Notes": "Proposed institutional match based on visual comparison with accession image; pending catalog confirmation.", "Rights": "IN COPYRIGHT; http://rightsstatements.org/vocab/InC/1.0/", "Disclaimer": "All rights reserved. Reproduction or redistribution requires written permission from Jackson State University.", "Contributing institution": "Jackson State University.", "Collection": "Jackson State University African Art Collection.", "Source": "JSU permanent collection", "Digital repository": "JSUMS ART.", "Digital collection": "African Art, Jackson State University.", "File size": "", "File extension": "", "Width": "", "Height": "", "Color space": "", "Date digital": "", "Capture method": "", "Processing software": "", "Master image": "", "Record created by": "", "Hidden notes": "Scaffold record generated from the local object inventory. Review and replace provisional values during cataloging. Provisional title derived from numeric filename.", "Custom searches": "", "IP resolution": "", "Transcript": "", "File name": "5.png", "culture_community": "Tabwa", "people_ethnolinguistic_group": "", "place_of_creation": "Democratic Republic of the Congo", "place_of_use": "", "materials": "Carved wood, metal tacks/studs", "technique": "", "object_type": "", "function_use": "", "period_dynasty": "late 19th century", "provenance": "", "acquisition_context": "", "preferred_term": "", "legacy_title": "", "attribution_confidence": "", "cultural_sensitivity_note": "", "youtubeid": "", "vimeoid": "", "latitude": "-2.8797", "longitude": "23.6560", "format": "image/png"}'::jsonb) on conflict (object_name) do update set title = excluded.title, culture_community = excluded.culture_community, geographic_location = excluded.geographic_location, file_name = excluded.file_name, asset_format = excluded.asset_format, record = excluded.record;
insert into public.catalog_records (object_name, title, culture_community, geographic_location, file_name, asset_format, record) values ('coll006', 'Untitled object 6', 'Songye', 'Democratic Republic of the Congo', '6.png', 'image/png', '{"Object name": "coll006", "Identifier": "JA-2006-05", "Alternate ID": "", "Title": "Untitled object 6", "Alternate title(s)": "", "Replaces": "", "Replaced by": "", "Description": "This mask is a male kifwebe associated with the Songye people and the Bwadi Bwa Kifwebe society. Characterized by an elongated form, half-closed eyes, pronounced facial planes, and a raffia beard, male kifwebe masks embody aggressive spiritual power used to enforce social order. Such masks appeared in masquerades addressing conflict, discipline, and communal regulation, where movement and costume amplified their intimidating presence.", "Creator": "", "Searchable date": "1900", "Date": "late 19th–early 20th century", "Coverage (time period)": "late 19th–early 20th century", "Time period": "", "Subject": "social regulation; ritual enforcement; spiritual power; masquerade; performance", "Mississippi county": "", "Geographic location": "Democratic Republic of the Congo", "Resource type": "Physical Object", "Format": "", "Media format": "Object", "Language": "", "Language code": "", "Publisher": "Jackson State University. (electronic version); JSUMS ART. (electronic version)", "Contributors": "", "Notes": "Proposed institutional match based on visual comparison with accession image; likely but pending catalog confirmation.", "Rights": "IN COPYRIGHT; http://rightsstatements.org/vocab/InC/1.0/", "Disclaimer": "All rights reserved. Reproduction or redistribution requires written permission from Jackson State University.", "Contributing institution": "Jackson State University.", "Collection": "Jackson State University African Art Collection.", "Source": "JSU Permanent Collection", "Digital repository": "JSUMS ART.", "Digital collection": "African Art, Jackson State University.", "File size": "", "File extension": "", "Width": "", "Height": "", "Color space": "", "Date digital": "", "Capture method": "", "Processing software": "", "Master image": "", "Record created by": "", "Hidden notes": "Scaffold record generated from the local object inventory. Review and replace provisional values during cataloging. Provisional title derived from numeric filename.", "Custom searches": "", "IP resolution": "", "Transcript": "", "File name": "6.png", "culture_community": "Songye", "people_ethnolinguistic_group": "", "place_of_creation": "Democratic Republic of the Congo", "place_of_use": "", "materials": "Carved wood, plant fiber (raffia), feathers", "technique": "", "object_type": "", "function_use": "", "period_dynasty": "late 19th–early 20th century", "provenance": "", "acquisition_context": "", "preferred_term": "", "legacy_title": "", "attribution_confidence": "", "cultural_sensitivity_note": "", "youtubeid": "", "vimeoid": "", "latitude": "-2.8797", "longitude": "23.6560", "format": "image/png"}'::jsonb) on conflict (object_name) do update set title = excluded.title, culture_community = excluded.culture_community, geographic_location = excluded.geographic_location, file_name = excluded.file_name, asset_format = excluded.asset_format, record = excluded.record;
insert into public.catalog_records (object_name, title, culture_community, geographic_location, file_name, asset_format, record) values ('coll007', 'Untitled object 7', 'Bembe', 'Democratic Republic of the Congo', '7.png', 'image/png', '{"Object name": "coll007", "Identifier": "JA-2006-06", "Alternate ID": "", "Title": "Untitled object 7", "Alternate title(s)": "", "Replaces": "", "Replaced by": "", "Description": "This mask is attributed to the Bembe people and reflects Central African masking traditions associated with initiation, healing, and social transition. Characterized by a rounded form, large circular eye surrounds, and red and white painted facial zones, the mask emphasizes visual contrast and presence rather than aggressive abstraction. Raffia elements formed part of the masquerade costume, activating the mask through movement and performance within community rituals.", "Creator": "", "Searchable date": "1900", "Date": "late 19th–early 20th century", "Coverage (time period)": "late 19th–early 20th century", "Time period": "", "Subject": "initiation; healing; masquerade; social transition; performance", "Mississippi county": "", "Geographic location": "Democratic Republic of the Congo", "Resource type": "Physical Object", "Format": "", "Media format": "Object", "Language": "", "Language code": "", "Publisher": "Jackson State University. (electronic version); JSUMS ART. (electronic version)", "Contributors": "", "Notes": "Proposed institutional match based on visual comparison with accession image; pending catalog confirmation.", "Rights": "IN COPYRIGHT; http://rightsstatements.org/vocab/InC/1.0/", "Disclaimer": "All rights reserved. Reproduction or redistribution requires written permission from Jackson State University.", "Contributing institution": "Jackson State University.", "Collection": "Jackson State University African Art Collection.", "Source": "JSU Permanent Collection", "Digital repository": "JSUMS ART.", "Digital collection": "African Art, Jackson State University.", "File size": "", "File extension": "", "Width": "", "Height": "", "Color space": "", "Date digital": "", "Capture method": "", "Processing software": "", "Master image": "", "Record created by": "", "Hidden notes": "Scaffold record generated from the local object inventory. Review and replace provisional values during cataloging. Provisional title derived from numeric filename.", "Custom searches": "", "IP resolution": "", "Transcript": "", "File name": "7.png", "culture_community": "Bembe", "people_ethnolinguistic_group": "", "place_of_creation": "Democratic Republic of the Congo", "place_of_use": "", "materials": "Carved wood, plant fiber (raffia), pigment", "technique": "", "object_type": "", "function_use": "", "period_dynasty": "late 19th–early 20th century", "provenance": "", "acquisition_context": "", "preferred_term": "", "legacy_title": "", "attribution_confidence": "", "cultural_sensitivity_note": "", "youtubeid": "", "vimeoid": "", "latitude": "-2.8797", "longitude": "23.6560", "format": "image/png"}'::jsonb) on conflict (object_name) do update set title = excluded.title, culture_community = excluded.culture_community, geographic_location = excluded.geographic_location, file_name = excluded.file_name, asset_format = excluded.asset_format, record = excluded.record;
insert into public.catalog_records (object_name, title, culture_community, geographic_location, file_name, asset_format, record) values ('coll008', 'Untitled object 8', 'Luba', 'Democratic Republic of the Congo', '8.png', 'image/png', '{"Object name": "coll008", "Identifier": "JA-2006-10", "Alternate ID": "", "Title": "Untitled object 8", "Alternate title(s)": "", "Replaces": "", "Replaced by": "", "Description": "This object is a lukasa, a memory board used by the Luba people as a mnemonic device for preserving and transmitting historical knowledge. Lukasa were employed by members of the Mbudye society to recall genealogies, political authority, moral teachings, and significant events. The incised surface patterns and sculpted seated figure functioned as tactile and visual prompts activated through recitation and instruction rather than visual reading alone.", "Creator": "", "Searchable date": "1900", "Date": "late 19th–early 20th century", "Coverage (time period)": "late 19th–early 20th century", "Time period": "", "Subject": "historical memory; political authority; oral tradition; mnemonic device; governance", "Mississippi county": "", "Geographic location": "Democratic Republic of the Congo", "Resource type": "Physical Object", "Format": "", "Media format": "Object", "Language": "", "Language code": "", "Publisher": "Jackson State University. (electronic version); JSUMS ART. (electronic version)", "Contributors": "", "Notes": "Proposed institutional match based on visual comparison with accession image; pending catalog confirmation.", "Rights": "IN COPYRIGHT; http://rightsstatements.org/vocab/InC/1.0/", "Disclaimer": "All rights reserved. Reproduction or redistribution requires written permission from Jackson State University.", "Contributing institution": "Jackson State University.", "Collection": "Jackson State University African Art Collection.", "Source": "JSU permanent collection", "Digital repository": "JSUMS ART.", "Digital collection": "African Art, Jackson State University.", "File size": "", "File extension": "", "Width": "", "Height": "", "Color space": "", "Date digital": "", "Capture method": "", "Processing software": "", "Master image": "", "Record created by": "", "Hidden notes": "Scaffold record generated from the local object inventory. Review and replace provisional values during cataloging. Provisional title derived from numeric filename.", "Custom searches": "", "IP resolution": "", "Transcript": "", "File name": "8.png", "culture_community": "Luba", "people_ethnolinguistic_group": "", "place_of_creation": "Democratic Republic of the Congo", "place_of_use": "", "materials": "Carved wood", "technique": "", "object_type": "", "function_use": "", "period_dynasty": "late 19th–early 20th century", "provenance": "", "acquisition_context": "", "preferred_term": "", "legacy_title": "", "attribution_confidence": "", "cultural_sensitivity_note": "", "youtubeid": "", "vimeoid": "", "latitude": "-2.8797", "longitude": "23.6560", "format": "image/png"}'::jsonb) on conflict (object_name) do update set title = excluded.title, culture_community = excluded.culture_community, geographic_location = excluded.geographic_location, file_name = excluded.file_name, asset_format = excluded.asset_format, record = excluded.record;
insert into public.catalog_records (object_name, title, culture_community, geographic_location, file_name, asset_format, record) values ('coll009', 'Untitled object 9', 'Baule', 'Côte d’Ivoire', '9.png', 'image/png', '{"Object name": "coll009", "Identifier": "JA-2006-11", "Alternate ID": "", "Title": "Untitled object 9", "Alternate title(s)": "", "Replaces": "", "Replaced by": "", "Description": "This standing female figure is attributed to the Baule people and represents a blolo bla, or female spirit spouse. Such figures embody ideals of beauty, balance, and spiritual composure and were maintained in personal shrines to honor spirit-world partners believed to affect health, fertility, and social wellbeing. The elongated neck, serene facial expression, and naturalistic proportions reflect Baule aesthetic values and beliefs about harmony between the human and spiritual realms.", "Creator": "", "Searchable date": "1900", "Date": "late 19th–early 20th century", "Coverage (time period)": "late 19th–early 20th century", "Time period": "", "Subject": "spirit spouse; fertility; spiritual harmony; personal shrine; idealized beauty", "Mississippi county": "", "Geographic location": "Côte d’Ivoire", "Resource type": "Physical Object", "Format": "", "Media format": "Object", "Language": "", "Language code": "", "Publisher": "Jackson State University. (electronic version); JSUMS ART. (electronic version)", "Contributors": "", "Notes": "Proposed institutional match based on visual comparison with accession image; likely but pending catalog confirmation.", "Rights": "IN COPYRIGHT; http://rightsstatements.org/vocab/InC/1.0/", "Disclaimer": "All rights reserved. Reproduction or redistribution requires written permission from Jackson State University.", "Contributing institution": "Jackson State University.", "Collection": "Jackson State University African Art Collection.", "Source": "JSU permanent collection", "Digital repository": "JSUMS ART.", "Digital collection": "African Art, 