insert into public.catalog_records (object_name, title, culture_community, geographic_location, file_name, asset_format, record) values ('coll010', 'Untitled object 10', 'Songye', 'Democratic Republic of the Congo', '10.png', 'image/png', '{"Object name": "coll010", "Identifier": "JA-2006-15", "Alternate ID": "", "Title": "Untitled object 10", "Alternate title(s)": "", "Replaces": "", "Replaced by": "", "Description": "This mask is attributed to the Songye people and is associated with the kifwebe masking tradition. Characterized by a tall central crest, narrow eye slits, and an elongated face, the mask embodies authoritative spiritual power linked to social regulation. Such masks were worn by members of the Bwadi Bwa Kifwebe society in performances intended to enforce moral order, address conflict, and maintain communal discipline.", "Creator": "", "Searchable date": "1900", "Date": "late 19th–early 20th century", "Coverage (time period)": "late 19th–early 20th century", "Time period": "", "Subject": "social regulation; moral authority; ritual enforcement; masquerade; performance", "Mississippi county": "", "Geographic location": "Democratic Republic of the Congo", "Resource type": "Physical Object", "Format": "", "Media format": "Object", "Language": "", "Language code": "", "Publisher": "Jackson State University. (electronic version); JSUMS ART. (electronic version)", "Contributors": "", "Notes": "Proposed institutional match based on visual comparison with accession image; pending catalog confirmation.", "Rights": "IN COPYRIGHT; http://rightsstatements.org/vocab/InC/1.0/", "Disclaimer": "All rights reserved. Reproduction or redistribution requires written permission from Jackson State University.", "Contributing institution": "Jackson State University.", "Collection": "Jackson State University African Art Collection.", "Source": "JSU permanent collection", "Digital repository": "JSUMS ART.", "Digital collection": "African Art, Jackson State University.", "File s