insert into public.catalog_records (object_name, title, culture_community, geographic_location, file_name, asset_format, record) values ('coll011', 'Untitled object 11', 'Banda / Nalu (Baga cultural region)', 'Guinea', '11.png', 'image/png', '{"Object name": "coll011", "Identifier": "JA-2005-01", "Alternate ID": "", "Title": "Untitled object 11", "Alternate title(s)": "", "Replaces": "", "Replaced by": "", "Description": "This banda (also known as kumbaruba) headdress represents a powerful composite being combining human and animal forms. The elongated horizontal structure incorporates a human face with Baga scarification and an elaborately braided female coiffure, joined to the jaw of a crocodile with visible teeth, along with antelope horns, a serpent’s body, and a chameleon’s tail. Historically a sacred figure associated with protection and male initiation rites, banda was accessible only to senior elders. Today it is performed in masquerades accompanied by drumming and dynamic choreography that evokes animal movement.", "Creator": "", "Searchable date": "1900", "Date": "late 19th–early 20th century", "Coverage (time period)": "late 19th–early 20th century", "Time period": "", "Subject": "masquerade; animal symbolism; initiation; protection; performance", "Mississippi county": "", "Geographic location": "Guinea", "Resource type": "Physical Object", "Format": "", "Media format": "Object", "Language": "", "Language code": "", "Publisher": "Jackson State University. (electronic version); JSUMS ART. (electronic version)", "Contributors": "", "Notes": "Proposed institutional match based on visual comparison with accession image; pending catalog confirmation.", "Rights": "IN COPYRIGHT; http://rightsstatements.org/vocab/InC/1.0/", "Disclaimer": "All rights reserved. Reproduction or redistribution requires written permission from Jackson State University.", "Contributing institution": "Jackson State University.", "Collection": "Jackson State University African Art Collec