insert into public.catalog_records (object_name, title, culture_community, geographic_location, file_name, asset_format, record) values ('coll012', 'Untitled object 12', 'Songye', 'Democratic Republic of the Congo', '12.png', 'image/png', '{"Object name": "coll012", "Identifier": "JA-2006-16", "Alternate ID": "", "Title": "Untitled object 12", "Alternate title(s)": "", "Replaces": "", "Replaced by": "", "Description": "A male kifwebe mask featuring a prominent sagittal crest and deep linear incisions filled with white pigment. The mask''s aggressive geometry and protruding features are designed to embody the mystical power of the bwadi bwa kifwebe society. It functioned in rituals of social regulation and political consolidation.", "Creator": "", "Searchable date": "1950", "Date": "20th century", "Coverage (time period)": "20th century", "Time period": "", "Subject": "social regulation; political authority; male initiation; ancestral mediation", "Mississippi county": "", "Geographic location": "Democratic Republic of the Congo", "Resource type": "Physical Object", "Format": "", "Media format": "Object", "Language": "", "Language code": "", "Publisher": "Jackson State University. (electronic version); JSUMS ART. (electronic version)", "Contributors": "", "Notes": "Proposed institutional match based on visual comparison with accession image; pending catalog confirmation.", "Rights": "IN COPYRIGHT; http://rightsstatements.org/vocab/InC/1.0/", "Disclaimer": "All rights reserved. Reproduction or redistribution requires written permission from Jackson State University.", "Contributing institution": "Jackson State University.", "Collection": "Jackson State University African Art Collection.", "Source": "JSU permanent collection", "Digital repository": "JSUMS ART.", "Digital collection": "African Art, Jackson State University.", "File size": "", "File extension": "", "Width": "", "Height": "", "Color space": "", "Date digital": "", "Capture method": "", "Processing software