insert into public.catalog_records (object_name, title, culture_community, geographic_location, file_name, asset_format, record) values ('coll014', 'Untitled object 14', 'Tetela or related central Congolese group', 'Democratic Republic of the Congo', '14.png', 'image/png', '{"Object name": "coll014", "Identifier": "", "Alternate ID": "", "Title": "Untitled object 14", "Alternate title(s)": "", "Replaces": "", "Replaced by": "", "Description": "A carved face mask with elongated oval form, large pierced eye openings, incised linear facial markings, small projecting ears, and partially open mouth with carved teeth, exhibiting a restrained and sober aesthetic consistent with central Congolese masking traditions, tentatively attributable to Tetela or a closely related neighboring group", "Creator": "", "Searchable date": "1950", "Date": "20th century", "Coverage (time period)": "20th century", "Time period": "", "Subject": "social mediation; ritual performance; initiation contexts; ancestral or moral symbolism", "Mississippi county": "", "Geographic location": "Democratic Republic of the Congo", "Resource type": "Physical Object", "Format": "", "Media format": "Object", "Language": "", "Language code": "", "Publisher": "Jackson State University. (electronic version); JSUMS ART. (electronic version)", "Contributors": "", "Notes": "", "Rights": "IN COPYRIGHT; http://rightsstatements.org/vocab/InC/1.0/", "Disclaimer": "All rights reserved. Reproduction or redistribution requires written permission from Jackson State University.", "Contributing institution": "Jackson State University.", "Collection": "Jackson State University African Art Collection.", "Source": "JSU permanent collection", "Digital repository": "JSUMS ART.", "Digital collection": "African Art, Jackson State University.", "File size": "", "File extension": "", "Width": "", "Height": "", "Color space": "", "Date digital": "", "Capture method": "", "Processing software": "", "Master image": "", "Record created b