insert into public.catalog_records (object_name, title, culture_community, geographic_location, file_name, asset_format, record) values ('coll015', 'Untitled object 15', 'Luba, Hemba, or related central Congolese group', 'Democratic Republic of the Congo', '15.png', 'image/png', '{"Object name": "coll015", "Identifier": "", "Alternate ID": "", "Title": "Untitled object 15", "Alternate title(s)": "", "Replaces": "", "Replaced by": "", "Description": "A standing male figure with elongated proportions, closed almond-shaped eyes, finely carved facial features, a patterned beard or scarification band along the jaw, hands resting on the abdomen, and pronounced genitalia, reflecting a calm and idealized sculptural style associated with central Congolese figurative traditions, conservatively attributable to Luba, Hemba, or a closely related group", "Creator": "", "Searchable date": "1950", "Date": "20th century", "Coverage (time period)": "20th century", "Time period": "", "Subject": "ancestral representation; commemoration; moral exemplarity; ritual or domestic veneration", "Mississippi county": "", "Geographic location": "Democratic Republic of the Congo", "Resource type": "Physical Object", "Format": "", "Media format": "Object", "Language": "", "Language code": "", "Publisher": "Jackson State University. (electronic version); JSUMS ART. (electronic version)", "Contributors": "", "Notes": "", "Rights": "IN COPYRIGHT; http://rightsstatements.org/vocab/InC/1.0/", "Disclaimer": "All rights reserved. Reproduction or redistribution requires written permission from Jackson State University.", "Contributing institution": "Jackson State University.", "Collection": "Jackson State University African Art Collection.", "Source": "JSU permanent collection", "Digital repository": "JSUMS ART.", "Digital collection": "African Art, Jackson State University.", "File size": "", "File extension": "", "Width": "", "Height": "", "Color space": "", "Date digital": "", "Capture method": "", "Pr