insert into public.catalog_records (object_name, title, culture_community, geographic_location, file_name, asset_format, record) values ('coll016', 'Untitled object 16', 'Lega or related eastern Central Congolese group', 'Democratic Republic of the Congo', '16.png', 'image/png', '{"Object name": "coll016", "Identifier": "", "Alternate ID": "", "Title": "Untitled object 16", "Alternate title(s)": "", "Replaces": "", "Replaced by": "", "Description": "A composite ritual object consisting of a curved buffalo horn fitted with a carved anthropomorphic wooden head and collar-like attachment at the proximal end, combining animal material and figurative carving in a form associated with portable ritual implements and symbolic authority, conservatively attributable to Lega or a closely related eastern Central Congolese group", "Creator": "", "Searchable date": "1950", "Date": "20th century", "Coverage (time period)": "20th century", "Time period": "", "Subject": "ritual display; initiation contexts; moral instruction; symbolic authority", "Mississippi county": "", "Geographic location": "Democratic Republic of the Congo", "Resource type": "Physical Object", "Format": "", "Media format": "Object", "Language": "", "Language code": "", "Publisher": "Jackson State University. (electronic version); JSUMS ART. (electronic version)", "Contributors": "", "Notes": "", "Rights": "IN COPYRIGHT; http://rightsstatements.org/vocab/InC/1.0/", "Disclaimer": "All rights reserved. Reproduction or redistribution requires written permission from Jackson State University.", "Contributing institution": "Jackson State University.", "Collection": "Jackson State University African Art Collection.", "Source": "JSU permanent collection", "Digital repository": "JSUMS ART.", "Digital collection": "African Art, Jackson State University.", "File size": "", "File extension": "", "Width": "", "Height": "", "Color space": "", "Date digital": "", "Capture method": "", "Processing software": "", "Master image"