insert into public.catalog_records (object_name, title, culture_community, geographic_location, file_name, asset_format, record) values ('coll017', 'Untitled object 17', 'Ngbaka', 'Democratic Republic of the Congo', '17.png', 'image/png', '{"Object name": "coll017", "Identifier": "", "Alternate ID": "", "Title": "Untitled object 17", "Alternate title(s)": "", "Replaces": "", "Replaced by": "", "Description": "A carved face mask with elongated triangular form, small circular eye perforations, pierced mouth, and a sculpted lizard affixed along the nasal ridge, a distinctive iconographic feature documented in northern Congolese masking traditions where reptiles symbolize vigilance, liminal power, and esoteric knowledge", "Creator": "", "Searchable date": "1950", "Date": "20th century", "Coverage (time period)": "20th century", "Time period": "", "Subject": "initiation rites; ritual performance; spiritual protection; mediation with hidden or dangerous forces", "Mississippi county": "", "Geographic location": "Democratic Republic of the Congo", "Resource type": "Physical Object", "Format": "", "Media format": "Object", "Language": "", "Language code": "", "Publisher": "Jackson State University. (electronic version); JSUMS ART. (electronic version)", "Contributors": "", "Notes": "", "Rights": "IN COPYRIGHT; http://rightsstatements.org/vocab/InC/1.0/", "Disclaimer": "All rights reserved. Reproduction or redistribution requires written permission from Jackson State University.", "Contributing institution": "Jackson State University.", "Collection": "Jackson State University African Art Collection.", "Source": "JSU permanent collection", "Digital repository": "JSUMS ART.", "Digital collection": "African Art, Jackson State University.", "File size": "", "File extension": "", "Width": "", "Height": "", "Color space": "", "Date digital": "", "Capture method": "", "Processing software": "", "Master image": "", "Record created by": "", "Hidden notes": "Scaffold record generated f