insert into public.catalog_records (object_name, title, culture_community, geographic_location, file_name, asset_format, record) values ('coll026', 'Untitled object 26', 'Songye', 'Democratic Republic of the Congo', '26.png', 'image/png', '{"Object name": "coll026", "Identifier": "", "Alternate ID": "", "Title": "Untitled object 26", "Alternate title(s)": "", "Replaces": "", "Replaced by": "", "Description": "A vertically oriented carved power figure with a faceted mask-like head set with metal studs, a cylindrical torso encircled by braided fiber bindings, and bifurcated legs, combining sculptural abstraction with applied materials to activate spiritual potency, closely aligning with documented Songye power figures associated with the bwadi bwa kifwebe complex", "Creator": "", "Searchable date": "1950", "Date": "20th century", "Coverage (time period)": "20th century", "Time period": "", "Subject": "ritual empowerment; protection; social regulation; spiritual mediation", "Mississippi county": "", "Geographic location": "Democratic Republic of the Congo", "Resource type": "Physical Object", "Format": "", "Media format": "Object", "Language": "", "Language code": "", "Publisher": "Jackson State University. (electronic version); JSUMS ART. (electronic version)", "Contributors": "", "Notes": "", "Rights": "IN COPYRIGHT; http://rightsstatements.org/vocab/InC/1.0/", "Disclaimer": "All rights reserved. Reproduction or redistribution requires written permission from Jackson State University.", "Contributing institution": "Jackson State University.", "Collection": "Jackson State University African Art Collection.", "Source": "JSU permanent collection", "Digital repository": "JSUMS ART.", "Digital collection": "African Art, Jackson State University.", "File size": "", "File extension": "", "Width": "", "Height": "", "Color space": "", "Date digital": "", "Capture method": "", "Processing software": "", "Master image": "", "Record created by": "", "Hidden notes": "Scaffold rec