insert into public.catalog_records (object_name, title, culture_community, geographic_location, file_name, asset_format, record) values ('coll032', 'Untitled object 32', 'Songye', 'Democratic Republic of the Congo', '32.png', 'image/png', '{"Object name": "coll032", "Identifier": "", "Alternate ID": "", "Title": "Untitled object 32", "Alternate title(s)": "", "Replaces": "", "Replaced by": "", "Description": "A small freestanding anthropomorphic power figure with a compact mask-like head surmounted by a short sagittal crest, pronounced arched brows, closed eyes, ringed neck, and a columnar body carved with diamond and linear geometric motifs, standing on a faceted base, closely comparable to documented small-scale Songye nkishi figures rather than Tabwa ancestral sculpture", "Creator": "", "Searchable date": "1950", "Date": "20th century", "Coverage (time period)": "20th century", "Time period": "", "Subject": "protective power; ritual empowerment; social regulation; spiritual mediation", "Mississippi county": "", "Geographic location": "Democratic Republic of the Congo", "Resource type": "Physical Object", "Format": "", "Media format": "Object", "Language": "", "Language code": "", "Publisher": "Jackson State University. (electronic version); JSUMS ART. (electronic version)", "Contributors": "", "Notes": "", "Rights": "IN COPYRIGHT; http://rightsstatements.org/vocab/InC/1.0/", "Disclaimer": "All rights reserved. Reproduction or redistribution requires written permission from Jackson State University.", "Contributing institution": "Jackson State University.", "Collection": "Jackson State University African Art Collection.", "Source": "JSU permanent collection", "Digital repository": "JSUMS ART.", "Digital collection": "African Art, Jackson State University.", "File size": "", "File extension": "", "Width": "", "Height": "", "Color space": "", "Date digital": "", "Capture method": "", "Processing software": "", "Master image": "", "Record created by": "", "Hidden not